styling.css:
.card {
 font-family: google sans;
 font-size: 20px;
 text-align: center;
 color: black;
 background-color: white;
}

.card {
  margin: 0;
  padding: 0;
  background: #f6f2ea;
  color: #202124;
  font-family: Inter, "Segoe UI", system-ui, -apple-system, BlinkMacSystemFont, "Noto Sans SC", "Microsoft YaHei", sans-serif;
  text-align: left;
}
.tc-shell {
  --topic: #2563eb;
  --accent: #38bdf8;
  box-sizing: border-box;
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: clamp(14px, 2vw, 30px);
  color: #202124;
  background: linear-gradient(120deg, color-mix(in srgb, var(--topic), transparent 91%), transparent 32%), linear-gradient(240deg, color-mix(in srgb, var(--accent), transparent 90%), transparent 34%), #f6f2ea;
}
.tc-frame {
  width: min(96vw, 1380px);
  min-height: min(88vh, 760px);
  display: grid;
  gap: clamp(16px, 2vw, 28px);
}
.tc-single { min-height: min(88vh, 760px); }
.tc-two { grid-template-columns: minmax(520px, 1.28fr) minmax(480px, 0.92fr); align-items: stretch; }
.tc-card {
  box-sizing: border-box;
  border: 1.5px solid color-mix(in srgb, var(--topic), #ffffff 34%);
  border-radius: 8px;
  background: #fffdf8;
  box-shadow: 0 24px 58px rgba(37, 31, 22, 0.13);
}
.tc-question {
  min-height: min(88vh, 760px);
  display: grid;
  grid-template-rows: auto 1fr auto;
  gap: 18px;
  padding: clamp(34px, 5vw, 76px);
}
.tc-answer {
  min-height: min(88vh, 760px);
  padding: clamp(22px, 2.6vw, 36px);
  background: rgba(255,255,255,0.9);
  overflow: visible;
}
.tc-kicker { color: var(--topic); font-size: 13px; line-height: 1.2; font-weight: 950; text-transform: uppercase; }
.tc-main { align-self: center; display: block; color: var(--topic); font-size: clamp(54px, 6.7vw, 98px); line-height: 1.08; font-weight: 900; letter-spacing: 0; overflow-wrap: anywhere; }
.tc-main > div:first-child, .tc-main strong, .tc-main b { color: var(--topic) !important; font-size: inherit !important; line-height: inherit !important; font-weight: 900 !important; }
.tc-front-copy { font-size: clamp(34px, 4.4vw, 64px); }
.tc-hint { color: #69645b; font-size: 13px; font-weight: 850; }
.tc-answer-body { color: #202124; font-size: clamp(17px, 1.25vw, 21px); line-height: 1.52; }
.tc-answer-body > div:first-child { margin: 0 0 16px; color: #111827; font-size: clamp(26px, 2vw, 34px) !important; line-height: 1.12 !important; font-weight: 950 !important; }
.tc-answer-body hr { height: 1px; border: 0; margin: 18px 0; background: #e3dbce; }
.tc-answer-body ul { display: grid; gap: 12px; margin: 14px 0 0; padding: 0; list-style: none; }
.tc-answer-body li, .tc-block { display: block; padding: 14px 16px; border-radius: 8px; background: #fff; box-shadow: 0 10px 22px rgba(37, 31, 22, 0.08); }
.tc-answer-body li b, .tc-block b { color: #111827; font-weight: 950; }
.tc-answer-body span[style*="color:#666"], .tc-answer-body span[style*="color: #666"], .tc-answer-body span[style*="color:#444"], .tc-answer-body span[style*="color: #444"] { color: #69645b !important; }
.tc-answer-body div[style], .tc-answer-body span[style] { font-family: inherit !important; }
.nightMode .card, .nightMode .tc-shell { background: #181715; color: #f6f2ea; }
.nightMode .tc-card { background: #22201d; color: #f6f2ea; border-color: color-mix(in srgb, var(--topic), #22201d 32%); }
.nightMode .tc-answer-body, .nightMode .tc-answer-body > div:first-child, .nightMode .tc-answer-body li b, .nightMode .tc-block b { color: #f6f2ea; }
.nightMode .tc-answer-body li, .nightMode .tc-block { background: #2b2925; }
@media (max-width: 980px) {
  .tc-frame { width: calc(100vw - 20px); min-height: auto; }
  .tc-two { grid-template-columns: 1fr; }
  .tc-question { min-height: 42vh; padding: 22px; }
  .tc-answer { min-height: auto; padding: 16px; }
  .tc-main { font-size: clamp(34px, 9vw, 58px); }
  .tc-front-copy { font-size: clamp(26px, 7vw, 44px); }
}

